import clsx from 'clsx';

export function MetricCard({ label, value, icon: Icon, tone = 'blue', helper, compact = false }) {
  const tones = {
    blue: 'bg-clinical-50 text-clinical-700 ring-clinical-100',
    green: 'bg-emerald-50 text-emerald-700 ring-emerald-100',
    yellow: 'bg-amber-50 text-amber-700 ring-amber-100',
    red: 'bg-red-50 text-red-700 ring-red-100',
    purple: 'bg-purple-50 text-purple-700 ring-purple-100'
  };
  const bars = {
    blue: 'from-clinical-500 to-clinical-300',
    green: 'from-emerald-500 to-emerald-300',
    yellow: 'from-amber-500 to-amber-300',
    red: 'from-red-500 to-red-300',
    purple: 'from-purple-500 to-purple-300'
  };
  return (
    <div className={clsx(
      'group relative overflow-hidden border border-white/70 bg-card-sheen shadow-soft backdrop-blur-xl transition duration-200 hover:-translate-y-1 hover:shadow-panel',
      compact ? 'rounded-[1.35rem] p-4' : 'rounded-[1.75rem] p-5'
    )}>
      <div className={clsx('absolute top-0 h-1 rounded-b-full bg-gradient-to-r', compact ? 'inset-x-4' : 'inset-x-5', bars[tone] || bars.blue)} />
      <div className={clsx('flex items-start justify-between', compact ? 'gap-3' : 'gap-4')}>
        <div className="min-w-0">
          <p className={clsx('font-black uppercase text-slate-400', compact ? 'text-[10px] tracking-[0.15em]' : 'text-[11px] tracking-[0.18em]')}>{label}</p>
          <p className={clsx('mt-2 truncate font-black tracking-tight text-slate-950', compact ? 'text-2xl' : 'text-3xl')}>{value}</p>
          {helper && <p className={clsx('mt-1 leading-5 text-slate-500', compact ? 'text-[11px]' : 'text-xs')}>{helper}</p>}
        </div>
        {Icon && (
          <div className={clsx('grid shrink-0 place-items-center rounded-2xl ring-1 transition group-hover:scale-105', compact ? 'h-10 w-10' : 'h-12 w-12', tones[tone] || tones.blue)}>
            <Icon className={clsx(compact ? 'h-5 w-5' : 'h-6 w-6')} />
          </div>
        )}
      </div>
    </div>
  );
}
